ValidationRule.errorConditionFormula:
AND( OR(contains( Text(leaseworks__Credit_Note__r.leaseworks__Invoice_Type__c) , 'Credit Note MR'), contains(Text(leaseworks__Credit_Note__r.leaseworks__Invoice_Type__c) , 'Credit Note Rent') )
  ,   leaseworks__Credit_Note__r.leaseworks__Total_Applied_Amount__c > leaseworks__Credit_Note__r.leaseworks__Total_Funded_Amount__c 
 )
